import { io } from 'socket.io-client';

const CHUNK_SIZE = 16384; // 16KB per chunk

class WebRTCHandler {
  constructor(signalingUrl, peerId, peerName, onPeersUpdate, onTransferProgress, onFileOffer) {
    this.socket = io(signalingUrl);
    this.peerId = peerId;
    this.peerName = peerName;
    this.onPeersUpdate = onPeersUpdate;
    this.onTransferProgress = onTransferProgress;
    this.onFileOffer = onFileOffer;

    // Map of SocketId -> RTCPeerConnection
    this.connections = new Map();
    // Map of SocketId -> RTCDataChannel
    this.dataChannels = new Map();

    this.pendingOutboundFiles = new Map();

    this.setupSignaling();
  }

  setupSignaling() {
    this.socket.on('connect', () => {
      console.log('🔗 Connected to Signaling Server', this.socket.id);
      this.socket.emit('register', { peerId: this.peerId, peerName: this.peerName });
    });

    this.socket.on('peers-update', (peers) => {
      // Exclude ourselves
      const otherPeers = peers.filter(p => p.socketId !== this.socket.id);
      if (this.onPeersUpdate) this.onPeersUpdate(otherPeers);
    });

    this.socket.on('webrtc-offer', async ({ offer, senderSocketId, senderName }) => {
      console.log(`📥 Received offer from ${senderName} (${senderSocketId})`);
      const peerConnection = this.createPeerConnection(senderSocketId);

      // Handle receiving data channels
      peerConnection.ondatachannel = (event) => {
        const receiveChannel = event.channel;
        receiveChannel.binaryType = 'arraybuffer';
        this.setupDataChannel(receiveChannel, senderSocketId, 'receiver');
      };

      await peerConnection.setRemoteDescription(new RTCSessionDescription(offer));
      const answer = await peerConnection.createAnswer();
      await peerConnection.setLocalDescription(answer);

      this.socket.emit('webrtc-answer', {
        answer,
        targetSocketId: senderSocketId
      });
    });

    this.socket.on('webrtc-answer', async ({ answer, senderSocketId }) => {
      console.log(`📥 Received answer from ${senderSocketId}`);
      const peerConnection = this.connections.get(senderSocketId);
      if (peerConnection) {
        await peerConnection.setRemoteDescription(new RTCSessionDescription(answer));
      }
    });

    this.socket.on('webrtc-ice-candidate', async ({ candidate, senderSocketId }) => {
      console.log(`❄️ Received ICE candidate from ${senderSocketId}`);
      const peerConnection = this.connections.get(senderSocketId);
      if (peerConnection) {
        try {
          await peerConnection.addIceCandidate(new RTCIceCandidate(candidate));
        } catch (e) {
          console.error('Error adding received ice candidate', e);
        }
      }
    });
  }

  createPeerConnection(targetSocketId) {
    const configuration = {
      iceServers: [
        { urls: 'stun:stun.l.google.com:19302' },
        { urls: 'stun:global.stun.twilio.com:3478' }
      ]
    };

    const peerConnection = new RTCPeerConnection(configuration);
    this.connections.set(targetSocketId, peerConnection);

    peerConnection.onicecandidate = (event) => {
      if (event.candidate) {
        this.socket.emit('webrtc-ice-candidate', {
          candidate: event.candidate,
          targetSocketId
        });
      }
    };

    peerConnection.onconnectionstatechange = () => {
      console.log(`Connection state with ${targetSocketId}: ${peerConnection.connectionState}`);
      if (peerConnection.connectionState === 'disconnected' || peerConnection.connectionState === 'failed') {
        this.connections.delete(targetSocketId);
        this.dataChannels.delete(targetSocketId);
      }
    };

    return peerConnection;
  }

  setupDataChannel(channel, targetSocketId, role) {
    this.dataChannels.set(targetSocketId, channel);

    let receiveBuffer = [];
    let receivedSize = 0;
    let expectedSize = 0;
    let expectedName = 'transfer_file';
    let startTime = 0;
    let lastProgressTime = 0;
    let totalChunks = 0;
    let receivedChunks = 0;

    channel.onopen = () => {
      console.log(`📡 Data Channel Open (${role}) with ${targetSocketId}`);
    };

    channel.onmessage = (event) => {
      if (typeof event.data === 'string') {
        // Metadata message
        try {
          const msg = JSON.parse(event.data);
          if (msg.type === 'file-offer') {
             if (this.onFileOffer) {
                 this.onFileOffer({
                    senderId: targetSocketId,
                    fileId: msg.fileId,
                    name: msg.name,
                    size: msg.size
                 }, () => {
                   // accept callback
                   if (channel.readyState === 'open') {
                     channel.send(JSON.stringify({ type: 'file-accept', fileId: msg.fileId }));
                   }
                 }, () => {
                   // reject callback
                   if (channel.readyState === 'open') {
                     channel.send(JSON.stringify({ type: 'file-reject', fileId: msg.fileId }));
                   }
                 });
             } else {
                 // Auto-accept if no UI handler exists
                 channel.send(JSON.stringify({ type: 'file-accept', fileId: msg.fileId }));
             }
          } else if (msg.type === 'file-accept') {
             const pending = this.pendingOutboundFiles.get(msg.fileId);
             if (pending && pending.channel === channel) {
                 this._beginSendFile(channel, targetSocketId, pending.file);
                 this.pendingOutboundFiles.delete(msg.fileId);
             }
          } else if (msg.type === 'file-reject') {
             this.pendingOutboundFiles.delete(msg.fileId);
             console.log(`User rejected file transfer ${msg.fileId}`);
          } else if (msg.type === 'file-meta') {
            expectedSize = msg.size;
            expectedName = msg.name;
            receiveBuffer = [];
            receivedSize = 0;
            receivedChunks = 0;
            totalChunks = Math.ceil(expectedSize / CHUNK_SIZE);
            startTime = Date.now();
            lastProgressTime = startTime;

            console.log(`📦 Incoming file: ${expectedName} (${expectedSize} bytes, ${totalChunks} chunks)`);
            if (this.onTransferProgress) {
              this.onTransferProgress({
                id: targetSocketId + '_' + expectedName,
                fileName: expectedName,
                progress: 0,
                type: 'download',
                status: 'metadata_received',
                totalSize: expectedSize,
                totalChunks,
                processedChunks: 0,
                speedBytesPerSec: 0
              });
            }
          }
        } catch(e) { console.error("Error parsing meta", e); }
      } else {
        // Binary Chunk
        receiveBuffer.push(event.data);
        receivedSize += event.data.byteLength;
        receivedChunks++;

        const now = Date.now();
        let speedBytesPerSec = 0;
        if (now - startTime > 0) {
          speedBytesPerSec = (receivedSize / ((now - startTime) / 1000));
        }

        const progress = Math.round((receivedSize / expectedSize) * 100);

        // Throttle UI updates slightly to prevent react re-render thrashing,
        // but ensure we send the 100% complete event.
        if (now - lastProgressTime > 100 || receivedSize === expectedSize) {
            lastProgressTime = now;
            if (this.onTransferProgress) {
              this.onTransferProgress({
                id: targetSocketId + '_' + expectedName,
                fileName: expectedName,
                progress: progress,
                type: 'download',
                status: receivedSize >= expectedSize ? 'complete' : 'receiving',
                receivedSize,
                totalSize: expectedSize,
                totalChunks,
                processedChunks: receivedChunks,
                speedBytesPerSec
              });
            }
        }

        if (receivedSize >= expectedSize) {
          console.log(`✅ File reception complete: ${expectedName}`);
          try {
            const blob = new Blob(receiveBuffer, { type: 'application/octet-stream' });
            const downloadUrl = URL.createObjectURL(blob);

            // Trigger download robustly
            const a = document.createElement('a');
            a.style.display = 'none';
            a.href = downloadUrl;
            a.download = expectedName;
            document.body.appendChild(a);
            a.click();

            // Clean up to prevent memory leaks
            setTimeout(() => {
                document.body.removeChild(a);
                URL.revokeObjectURL(downloadUrl);
            }, 1000);
          } catch(e) {
            console.error("Download trigger failed:", e);
          }
        }
      }
    };

    channel.onclose = () => {
      console.log(`📡 Data Channel Closed (${role}) with ${targetSocketId}`);
      this.dataChannels.delete(targetSocketId);
    };
  }

  async connectToPeer(targetSocketId) {
    if (this.connections.has(targetSocketId)) {
      console.log('Already connected or connecting to this peer.');
      return;
    }

    const peerConnection = this.createPeerConnection(targetSocketId);

    // As the caller, we create the data channel
    const dataChannel = peerConnection.createDataChannel('fileTransfer', {
      ordered: true, // Reliable transfer
      maxRetransmits: 3
    });
    dataChannel.binaryType = 'arraybuffer';

    this.setupDataChannel(dataChannel, targetSocketId, 'sender');

    const offer = await peerConnection.createOffer();
    await peerConnection.setLocalDescription(offer);

    this.socket.emit('webrtc-offer', {
      offer,
      targetSocketId
    });
  }

  sendFile(targetSocketId, file) {
    const channel = this.dataChannels.get(targetSocketId);
    if (!channel) {
      console.error('Data channel is not open. Please connect first.');
      return;
    }

    const beginOffer = () => {
      const fileId = Math.random().toString(36).substring(2, 15);
      this.pendingOutboundFiles.set(fileId, { channel, file, targetSocketId });
      channel.send(JSON.stringify({
         type: 'file-offer',
         fileId,
         name: file.name,
         size: file.size
      }));
    };

    if (channel.readyState !== 'open') {
      console.log('Channel connecting, queueing file transfer offer...');
      const oldOnOpen = channel.onopen;
      channel.onopen = (e) => {
        if (oldOnOpen) oldOnOpen(e);
        beginOffer();
      };
      return;
    }

    beginOffer();
  }

  _beginSendFile(channel, targetSocketId, file) {

    const meta = {
      type: 'file-meta',
      name: file.name,
      size: file.size,
      mime: file.type
    };
    channel.send(JSON.stringify(meta));

    const fileReader = new FileReader();
    let offset = 0;
    let sentChunks = 0;
    const totalChunks = Math.ceil(file.size / CHUNK_SIZE);
    const startTime = Date.now();
    let lastProgressTime = startTime;

    const readSlice = (o) => {
      const slice = file.slice(offset, o + CHUNK_SIZE);
      fileReader.readAsArrayBuffer(slice);
    };

    fileReader.onload = (e) => {
      channel.send(e.target.result);
      offset += e.target.result.byteLength;
      sentChunks++;

      const now = Date.now();
      let speedBytesPerSec = 0;
      if (now - startTime > 0) {
          speedBytesPerSec = (offset / ((now - startTime) / 1000));
      }

      const progress = Math.round((offset / file.size) * 100);

      // Throttle exact progress updates UI, but guarantee 100%
      if (now - lastProgressTime > 100 || offset >= file.size) {
          lastProgressTime = now;
          if (this.onTransferProgress) {
            this.onTransferProgress({
              id: targetSocketId + '_' + file.name,
              fileName: file.name,
              progress: progress,
              type: 'upload',
              status: offset >= file.size ? 'complete' : 'sending',
              sentSize: offset,
              totalSize: file.size,
              totalChunks,
              processedChunks: sentChunks,
              speedBytesPerSec
            });
          }
      }

      if (offset < file.size) {
        // Respect backpressure
        if (channel.bufferedAmount > channel.bufferedAmountLowThreshold) {
          channel.onbufferedamountlow = () => {
            channel.onbufferedamountlow = null;
            readSlice(offset);
          };
        } else {
          readSlice(offset);
        }
      } else {
        console.log(`✅ File sending complete: ${file.name}`);
      }
    };

    // Set a sensible low threshold for backpressure
    channel.bufferedAmountLowThreshold = CHUNK_SIZE * 4; 
    readSlice(0);
  }

  sendGroupFile(targetSocketIds, file) {
    // Simply wrap the sendFile pipeline for each target. The staggering of file-accept responses 
    // requires independent instances anyway for streaming buffer safety.
    targetSocketIds.forEach(targetId => {
      this.sendFile(targetId, file);
    });
  }

  disconnect() {
    this.connections.forEach(pc => pc.close());
    this.connections.clear();
    this.dataChannels.clear();
    this.socket.disconnect();
  }
}

export default WebRTCHandler;
